cssVarsTemplate:
@import "tailwincss";

:root {
  --background: light-dark(0 0% 100%, 240 10% 3.9%);
  --foreground: light-dark(240 10% 3.9%, 0 0% 98%);
  --card: light-dark(0 0% 100%, 240 10% 3.9%);
  --card-foreground: light-dark(240 10% 3.9%, 0 0% 98%);
  --popover: light-dark(0 0% 100%, 240 10% 3.9%);
  --popover-foreground: light-dark(240 10% 3.9%, 0 0% 98%);
  --primary: light-dark(240 5.9% 10%, 0 0% 98%);
  --primary-foreground: light-dark(0 0% 98%, 240 5.9% 10%);
  --secondary: light-dark(240 4.8% 95.9%, 240 3.7% 15.9%);
  --secondary-foreground: light-dark(240 5.9% 10%, 0 0% 98%);
  --muted: light-dark(240 4.8% 95.9%, 240 3.7% 15.9%);
  --muted-foreground: light-dark(240 3.8% 46.1%, 240 5% 64.9%);
  --accent: light-dark(240 4.8% 95.9%, 240 3.7% 15.9%);
  --accent-foreground: light-dark(240 5.9% 10%, 0 0% 98%);
  --destructive: light-dark(0 84.2% 60.2%, 0 62.8% 30.6%);
  --destructive-foreground: light-dark(0 0% 98%, 0 0% 98%);
  --border: light-dark(240 5.9% 90%, 240 3.7% 15.9%);
  --input: light-dark(240 5.9% 90%, 240 3.7% 15.9%);
  --ring: light-dark(240 10% 3.9%, 240 4.9% 83.9%);
  --radius: 0.5rem;
  --chart-1: light-dark(12 76% 61%, 220 70% 50%);
  --chart-2: light-dark(173 58% 39%, 160 60% 45%);
  --chart-3: light-dark(197 37% 24%, 30 80% 55%);
  --chart-4: light-dark(43 74% 66%, 280 65% 60%);
  --chart-5: light-dark(27 87% 67%, 340 75% 55%);
}

@layer base {
  * {
    @apply border-border;
  }
  body {
    @apply bg-background text-foreground;
  }
}
